#![no_main]
//! CSCI vProg guest for `ZkAllowlistTransfer` — generated by portrait-atelier (M3).
//! new_state_hash is computed over the NEW state derived from the portrait body
//! Return expression; entrypoint requires(...) are asserted in-guest.
//! Fields not referenced by the return expr are carried forward unchanged.
//! Journal: covenant_id[32] || new_state_hash[32] || rule_hash[32] || seq[8 LE]
risc0_zkvm::guest::entry!(main);

use risc0_zkvm::guest::env;
use sha2::{Digest, Sha256};

/// Auto-derived KovId: sha256(silverc compiled script bytes).
const COV_ID: [u8; 32] = [0xd2, 0xfe, 0x8c, 0xf1, 0xaf, 0xa3, 0x37, 0xf1, 0x98, 0x09, 0x3d, 0xdc, 0xe5, 0x29, 0xb0, 0x70, 0x5e, 0xbf, 0x7b, 0x09, 0x67, 0xf6, 0x26, 0x0d, 0x01, 0x93, 0xf4, 0x28, 0xea, 0x7d, 0xfe, 0xb7];

fn sha256_bytes(data: &[u8]) -> [u8; 32] {
    let mut h = Sha256::new();
    h.update(data);
    h.finalize().into()
}

fn encode_state(owner: [u8; 32], allowlist_root: [u8; 32], commitment: [u8; 32], nullifier: [u8; 32], seq: i64) -> Vec<u8> {
    let mut out: Vec<u8> = Vec::new();
    out.extend_from_slice(&owner);
    out.extend_from_slice(&allowlist_root);
    out.extend_from_slice(&commitment);
    out.extend_from_slice(&nullifier);
    out.extend_from_slice(&seq.to_le_bytes());
    out
}

/// Verify the `membership_rule` VProg transition and return the 104-byte CSCI journal.
fn verify_membership_rule(covenant_id: [u8; 32], prev_seq: u64, owner: [u8; 32], allowlist_root: [u8; 32], commitment: [u8; 32], nullifier: [u8; 32], seq: i64) -> [u8; 104] {
    // ---------------------------------------------------------------------
    // INPUTS (typed):
    //   covenant_id: [u8; 32]   — KovId of the covenant this proof binds to
    //   prev_seq:    u64        — sequence of the prev on-chain state
    //   owner: [u8; 32]   — prev state field (carried from main env::read)
    //   allowlist_root: [u8; 32]   — prev state field (carried from main env::read)
    //   commitment: [u8; 32]   — prev state field (carried from main env::read)
    //   nullifier: [u8; 32]   — prev state field (carried from main env::read)
    //   seq: i64   — prev state field (carried from main env::read)
    //   next_commitment: [u8; 32]   — transition arg (env::read below)
    //   next_nullifier: [u8; 32]   — transition arg (env::read below)
    // JOURNAL (104 bytes, committed at the end):
    //   [0..32)   covenant_id
    //   [32..64)  new_state_hash = sha256(encode_state(NEW fields))
    //   [64..96)  rule_hash      = sha256(entry-point name)
    //   [96..104) seq (u64 LE)   = prev_seq + 1
    // ---------------------------------------------------------------------
    let next_commitment: [u8; 32] = env::read();
    let next_nullifier: [u8; 32] = env::read();
    // ===== DEVELOPER PREDICATE HOOK (author the heavy proof logic here) =====
    #[allow(unused_variables, clippy::too_many_arguments)]
    fn predicate(owner: [u8; 32], allowlist_root: [u8; 32], commitment: [u8; 32], nullifier: [u8; 32], seq: i64, next_commitment: [u8; 32], next_nullifier: [u8; 32]) -> bool {
        // TODO: author the heavy off-chain claim over the typed inputs above
        // (fold / Pedersen open / Merkle membership / policy circuit). Returns true
        // by default — the guest does NOT yet prove this claim.
        true
    }
    assert!(predicate(owner, allowlist_root, commitment, nullifier, seq, next_commitment, next_nullifier), "vprog predicate failed");
    // ===== END DEVELOPER PREDICATE HOOK =====
    let new_commitment = next_commitment;
    let new_nullifier = next_nullifier;
    let new_seq = seq + 1;
    let new_state_bytes = encode_state(owner, allowlist_root, new_commitment, new_nullifier, new_seq);
    let journal_state_hash = sha256_bytes(&new_state_bytes);
    let rule_hash = sha256_bytes(b"membership_rule"); // rule = entry point name
    let journal_seq = prev_seq.checked_add(1).expect("seq overflow");

    let mut journal = [0u8; 104];
    journal[..32].copy_from_slice(&covenant_id);
    journal[32..64].copy_from_slice(&journal_state_hash);
    journal[64..96].copy_from_slice(&rule_hash);
    journal[96..].copy_from_slice(&journal_seq.to_le_bytes());
    journal
}

fn main() {
    let covenant_id = COV_ID; // auto-derived KovId
    let prev_seq: u64 = env::read();
    let owner: [u8; 32] = env::read();
    let allowlist_root: [u8; 32] = env::read();
    let commitment: [u8; 32] = env::read();
    let nullifier: [u8; 32] = env::read();
    let seq: i64 = env::read();
    let journal = verify_membership_rule(covenant_id, prev_seq, owner, allowlist_root, commitment, nullifier, seq);
    env::commit_slice(&journal);
}
